func verifyPackageChecksum(pkgPath, version string) error {
	// Query official Go checksum database
	url := fmt.Sprintf("https://sum.golang.org/lookup/%s@%s", pkgPath, version)
	
	client := &http.Client{
		Timeout: 10,
	}
	
	resp, err := client.Get(url)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return fmt.Errorf("checksum verification failed for %s@%s", pkgPath, version)
	}

	body, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024))
	if err != nil {
		return err
	}

	hash := sha256.Sum256(body)
	checksum := hex.EncodeToString(hash[:])
	
	fmt.Printf("Verified %s@%s (checksum: %s...)\n", pkgPath, version, checksum[:16])
	
	return nil
}